import { Link } from "react-router-dom";

const Sidebar = () => {
  return (
    <div className="sidebar">
      <h3>ADMIN</h3>

      <ul>
        <li>
          <Link to="/admin">DASHBOARD</Link>
        </li>

        <li>
          <Link to="/admin/patients/register">
            PATIENT REGISTRATION
