          <Link to="/admin/patients/visit">
            PATIENT VISIT
          </Link>
        </li>

        <li>
          <Link to="/admin/emr">EMR</Link>
        </li>

        <li>
          <Link to="/admin/billing">BILLING</Link>
        </li>
      </ul>
    </div>
  );
};

export default Sidebar;
